module top_module(
    input                       clk,

    input       [widthad-1:0]   wraddress,
    input                       wren,
    input       [width-1:0]     data,

    input       [widthad-1:0]   rdaddress,
    output reg  [width-1:0]     q
);parameter width     = 1;
parameter widthad   = 1;

reg [width-1:0] mem [(2**widthad)-1:0];

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if(wren) mem[wraddress] <= data;

    q <= mem[rdaddress];
end

endmodule
